from __future__ import annotations

import argparse
import csv
import json
from dataclasses import dataclass
from datetime import datetime, timedelta
from pathlib import Path
from typing import Any

import pandas as pd

PROJECT_ROOT = Path(__file__).resolve().parents[1]
REPORT_DIR = PROJECT_ROOT / "research" / "reports"
CONFIG_PATH = PROJECT_ROOT / "config" / "live_trading_v1.json"
BENCH_CSV = Path("/Users/ling/.openclaw/workspace/quant_projects/daily_stock_analysis/index_000852_SH.csv")
A_STOCK_CSV = Path("/Users/ling/.openclaw/workspace/data/a_stock_history.csv")


@dataclass
class RuntimeState:
    date_tag: str
    mode: str
    halt_new_buy: bool
    halt_reason: str


@dataclass
class PrecheckResult:
    passed: bool
    reasons: list[str]
    warnings: list[str]


def load_json(path: Path) -> dict[str, Any]:
    return json.loads(path.read_text(encoding="utf-8"))


def apply_gray_policy(config: dict[str, Any], available_cash: float, runtime: RuntimeState) -> dict[str, Any]:
    """
    把 Top2 灰度策略接入 live_trading_v1 执行入口：
    - 根据 active_phase 限制当日新增预算上限
    - 可选覆盖单票上限/现金缓冲
    - G0 或配置异常时可自动停买
    """
    gray_cfg = config.get("rd_agent_top2_gray", {}) or {}
    ctx: dict[str, Any] = {
        "enabled": bool(gray_cfg.get("enabled", False)),
        "phase": gray_cfg.get("active_phase", ""),
        "policy_config": gray_cfg.get("policy_config", ""),
        "policy_loaded": False,
        "phase_cash_cap": 0.0,
        "effective_add_ratio": None,
        "notes": [],
    }

    if not ctx["enabled"]:
        return ctx

    policy_path = Path(str(ctx["policy_config"]))
    if not policy_path.is_absolute():
        policy_path = (PROJECT_ROOT / policy_path).resolve()

    if not policy_path.exists():
        ctx["notes"].append(f"灰度策略文件不存在: {policy_path}")
        if bool(gray_cfg.get("auto_halt_if_phase_unknown", True)):
            runtime.mode = "halt"
            runtime.halt_new_buy = True
            runtime.halt_reason = "灰度策略文件缺失，自动停买"
        return ctx

    policy = load_json(policy_path)
    ctx["policy_loaded"] = True

    phase = str(ctx["phase"] or "").strip()
    phase_caps = (((policy.get("capital") or {}).get("phase_cash_cap")) or {})

    if phase not in phase_caps:
        ctx["notes"].append(f"未知灰度阶段: {phase}")
        if bool(gray_cfg.get("auto_halt_if_phase_unknown", True)):
            runtime.mode = "halt"
            runtime.halt_new_buy = True
            runtime.halt_reason = f"灰度阶段无效({phase})，自动停买"
        return ctx

    phase_cap = parse_float(phase_caps.get(phase), 0.0)
    ctx["phase_cash_cap"] = phase_cap

    ex = config.get("execution", {})
    current_add_ratio = parse_float(ex.get("max_daily_add_ratio"), 0.25)

    if available_cash > 0:
        phase_add_ratio = max(0.0, min(1.0, phase_cap / available_cash))
    else:
        phase_add_ratio = 0.0

    effective_add_ratio = min(current_add_ratio, phase_add_ratio)
    ex["max_daily_add_ratio"] = round(effective_add_ratio, 6)
    ctx["effective_add_ratio"] = float(ex["max_daily_add_ratio"])

    cap_single = parse_float((((policy.get("capital") or {}).get("max_single_position_ratio"))), 0.0)
    if cap_single > 0:
        current_single = parse_float(ex.get("max_single_position_ratio"), 0.08)
        ex["max_single_position_ratio"] = round(min(current_single, cap_single), 6)

    cap_buffer = parse_float((((policy.get("capital") or {}).get("cash_buffer_ratio"))), 0.0)
    if cap_buffer > 0:
        current_buffer = parse_float(ex.get("cash_buffer_ratio"), 0.1)
        ex["cash_buffer_ratio"] = round(max(current_buffer, cap_buffer), 6)

    config["execution"] = ex

    if phase == "G0_shadow":
        runtime.mode = "halt"
        runtime.halt_new_buy = True
        runtime.halt_reason = "灰度阶段=G0_shadow，仅影子运行"

    ctx["notes"].append(
        f"phase={phase}, add_ratio={current_add_ratio:.4f}->{ex['max_daily_add_ratio']:.4f}, phase_cash_cap={phase_cap:.0f}"
    )
    return ctx


def latest_file(pattern: str) -> Path:
    files = sorted(REPORT_DIR.glob(pattern))
    if not files:
        raise FileNotFoundError(f"未找到文件: {pattern}")
    return files[-1]


def parse_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(str(value).replace(",", "").strip())
    except Exception:
        return default


def parse_int(value: Any, default: int = 0) -> int:
    try:
        return int(float(str(value).replace(",", "").strip()))
    except Exception:
        return default


def first_non_empty(row: dict[str, Any], keys: list[str]) -> Any:
    for key in keys:
        value = row.get(key)
        if value is None:
            continue
        text = str(value).strip()
        if text != "" and text.lower() != "nan":
            return value
    return None


def load_market_guard_pct() -> float:
    if not BENCH_CSV.exists():
        return 0.0
    df = pd.read_csv(BENCH_CSV)
    close = pd.to_numeric(df["close"], errors="coerce")
    ret = close.pct_change().fillna(0.0)
    if ret.empty:
        return 0.0
    return float(ret.iloc[-1] * 100)


def normalize_ts_code(ts_code: str) -> str:
    return str(ts_code or "").strip().upper()


def is_a_share_stock(ts_code: str) -> bool:
    code = normalize_ts_code(ts_code)
    if "." not in code:
        return False
    symbol, market = code.split(".", 1)
    if market not in ("XSHG", "XSHE"):
        return False
    # 上交所A股: 600/601/603/605/688; 深交所A股: 000/001/002/003/300/301
    if market == "XSHG":
        return symbol.startswith(("600", "601", "603", "605", "688"))
    return symbol.startswith(("000", "001", "002", "003", "300", "301"))


def parse_row_datetime(value: Any) -> datetime | None:
    if value is None:
        return None
    text = str(value).strip()
    if not text:
        return None
    for fmt in ("%Y-%m-%d %H:%M:%S +0800", "%Y-%m-%d %H:%M:%S", "%Y-%m-%d"):
        try:
            return datetime.strptime(text, fmt)
        except Exception:
            continue
    return None


def to_tushare_code(ts_code: str) -> str:
    code = normalize_ts_code(ts_code)
    if not code:
        return ""
    if code.endswith(".SH") or code.endswith(".SZ"):
        return code
    if "." not in code:
        return ""
    symbol, market = code.split(".", 1)
    if market == "XSHG":
        return f"{symbol}.SH"
    if market == "XSHE":
        return f"{symbol}.SZ"
    return ""


def load_adv20_map(path: Path, min_trade_date: str = "") -> dict[str, float]:
    if not path.exists():
        return {}

    df = pd.read_csv(path, usecols=["ts_code", "trade_date", "amount"])
    if df.empty:
        return {}

    if min_trade_date:
        try:
            min_date = int(min_trade_date.replace("-", ""))
            df = df[pd.to_numeric(df["trade_date"], errors="coerce") >= min_date]
        except Exception:
            pass

    df["ts_code"] = df["ts_code"].astype(str).str.upper().str.strip()
    df["trade_date"] = pd.to_numeric(df["trade_date"], errors="coerce")
    df["amount"] = pd.to_numeric(df["amount"], errors="coerce").fillna(0.0) * 1000.0
    df = df.dropna(subset=["trade_date"])

    if df.empty:
        return {}

    df = df.sort_values(["ts_code", "trade_date"])
    adv20 = (
        df.groupby("ts_code", group_keys=False)
        .tail(20)
        .groupby("ts_code", as_index=False)["amount"]
        .mean()
    )
    return dict(zip(adv20["ts_code"], adv20["amount"]))


def load_holdings_map(path: Path | None) -> dict[str, int]:
    if path is None or not path.exists():
        return {}
    with path.open("r", encoding="utf-8", newline="") as f:
        rows = list(csv.DictReader(f))
    holdings: dict[str, int] = {}
    for row in rows:
        code = normalize_ts_code(first_non_empty(row, ["ts_code", "symbol", "security"]))
        if not code:
            continue
        qty = parse_int(first_non_empty(row, ["qty", "shares", "position", "total_amount", "current_qty"]), 0)
        if qty > 0:
            holdings[code] = holdings.get(code, 0) + qty
    return holdings


def net_pending_orders(pending_rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    bucket: dict[str, dict[str, Any]] = {}
    for row in pending_rows:
        code = normalize_ts_code(row.get("ts_code", ""))
        if not code:
            continue
        side = str(row.get("side", "")).upper().strip()
        qty_raw = first_non_empty(row, ["delta_qty", "source_qty", "target_qty", "current_qty"])
        qty = parse_int(qty_raw, 0)
        if qty == 0:
            continue
        signed = qty if side == "BUY" else -abs(qty)

        if code not in bucket:
            bucket[code] = {
                "ts_code": code,
                "signed_qty": 0,
                "rows": [],
            }
        bucket[code]["signed_qty"] += signed
        bucket[code]["rows"].append(row)

    net_rows: list[dict[str, Any]] = []
    for code, payload in bucket.items():
        signed = int(payload["signed_qty"])
        if signed == 0:
            continue
        row = payload["rows"][-1].copy()
        row["ts_code"] = code
        row["side"] = "BUY" if signed > 0 else "SELL"
        row["delta_qty"] = abs(signed)
        row["source_qty"] = abs(signed)
        row["notes"] = f"netted_from_{len(payload['rows'])}_rows"
        net_rows.append(row)
    return net_rows


def decide_mode(live_payload: dict[str, Any], config: dict[str, Any], index_ret_pct: float) -> RuntimeState:
    combo = live_payload.get("combo_v1", {})
    max_dd = parse_float(combo.get("max_drawdown_pct"), 0.0)
    sharpe = parse_float(combo.get("sharpe"), 0.0)
    target_dd = parse_float(config["targets"]["max_drawdown_max_pct"], 25.0)
    index_halt = parse_float(config["risk"]["index_halt_threshold_pct"], -1.5)

    mode = "normal"
    halt_new_buy = False
    halt_reason = ""

    if index_ret_pct <= index_halt:
        mode = "halt"
        halt_new_buy = True
        halt_reason = f"index_guard触发: 中证2000单日{index_ret_pct:.2f}% <= {index_halt:.2f}%"
    elif max_dd > target_dd:
        mode = "cautious"
        halt_new_buy = True
        halt_reason = f"组合历史回撤{max_dd:.2f}% > 目标上限{target_dd:.2f}%"
    elif sharpe < 0.8:
        mode = "cautious"

