    if code_col is None or qty_col is None:
        return pd.DataFrame()

    out = pd.DataFrame()
    out["symbol"] = d[code_col].map(normalize_code)
    out["name"] = d[name_col].astype(str).str.strip() if name_col else ""
    out["quantity"] = pd.to_numeric(d[qty_col], errors="coerce").fillna(0).astype(int)
    out["cost_price"] = pd.to_numeric(d[cost_col], errors="coerce") if cost_col else np.nan
    out["last_price"] = pd.to_numeric(d[price_col], errors="coerce") if price_col else np.nan
    out["asset_type"] = out["symbol"].map(lambda s: "fund" if str(s).startswith(("5", "1", "15")) else "stock")
    out["source_file"] = source_file

    out = out[out["symbol"].ne("") & (out["quantity"] > 0)].copy()
    return out.reset_index(drop=True)


def normalize_side(value: Any) -> str:
    text = str(value or "").strip().upper()
    if not text or text == "NAN":
        return ""
    if any(k in text for k in ["买", "BUY", "B", "证券买入"]):
        return "BUY"
    if any(k in text for k in ["卖", "SELL", "S", "证券卖出"]):
        return "SELL"
    return text


def normalize_trades(df: pd.DataFrame, source_file: str) -> pd.DataFrame:
    if df.empty:
        return pd.DataFrame()
    d = df.copy()
    if {"source_kind", "notes", "trade_date", "symbol", "side", "qty"}.issubset(set(d.columns)):
        return pd.DataFrame()
    d.columns = [str(c).strip() for c in d.columns]

    code_col = first_col(d, ["证券代码", "股票代码", "代码", "symbol", "ts_code"])
    name_col = first_col(d, ["证券名称", "股票名称", "名称", "name"])
    side_col = first_col(d, ["买卖标志", "交易类型", "买卖", "方向", "操作", "委托类别", "side"])
    qty_col = first_col(d, ["成交数量", "成交股数", "数量", "委托数量", "qty"])
    price_col = first_col(d, ["成交均价", "成交价格", "成交价", "价格", "price"])
    amount_col = first_col(d, ["成交金额", "发生金额", "amount"])
    date_col = first_col(d, ["成交日期", "日期", "委托日期", "trade_date"])
    time_col = first_col(d, ["成交时间", "时间", "委托时间", "trade_time"])

    if code_col is None or qty_col is None:
        return pd.DataFrame()

    out = pd.DataFrame()
    out["symbol"] = d[code_col].map(normalize_code)
    out["name"] = d[name_col].astype(str).str.strip() if name_col else ""
    out["side"] = d[side_col].map(normalize_side) if side_col else ""
    out["qty"] = pd.to_numeric(d[qty_col], errors="coerce").fillna(0).astype(int)
    out["price"] = pd.to_numeric(d[price_col], errors="coerce") if price_col else np.nan
    out["amount"] = pd.to_numeric(d[amount_col], errors="coerce") if amount_col else out["qty"] * out["price"]

    if date_col:
        date_text = d[date_col].astype(str).str.strip()
    else:
        date_text = ""
    if time_col:
        time_text = d[time_col].astype(str).str.strip()
    else:
        time_text = ""

    if isinstance(date_text, pd.Series):
        out["trade_date"] = pd.to_datetime(date_text, errors="coerce").dt.strftime("%Y-%m-%d")
    else:
        out["trade_date"] = ""
    if isinstance(time_text, pd.Series):
        out["trade_time"] = time_text
    else:
        out["trade_time"] = ""

    out["source_file"] = source_file

    missing_side = out["side"].eq("")
    out.loc[missing_side & (out["qty"] > 0), "side"] = "BUY"
    out.loc[missing_side & (out["qty"] < 0), "side"] = "SELL"
    out["qty"] = out["qty"].abs()

    out = out[out["symbol"].ne("") & (out["qty"] > 0)].copy()
    return out.reset_index(drop=True)


def write_portfolio(holdings_df: pd.DataFrame) -> Path:
    CONFIG_DIR.mkdir(parents=True, exist_ok=True)
    out = holdings_df[["symbol", "asset_type", "name", "quantity", "cost_price"]].copy()
    out.to_csv(PORTFOLIO_PATH, index=False, encoding="utf-8-sig")
    return PORTFOLIO_PATH


def main() -> None:
    parser = argparse.ArgumentParser(description="自动同步同花顺导出：持仓/成交 -> 系统可用CSV")
    parser.add_argument("--scan-dir", action="append", default=[], help="附加扫描目录，可多次传入")
    parser.add_argument("--lookback-days", type=int, default=10, help="回看最近N天文件")
    args = parser.parse_args()

    scan_dirs = list(DEFAULT_SCAN_DIRS)
    for x in args.scan_dir:
        scan_dirs.append(Path(x).expanduser().resolve())

    REPORT_DIR.mkdir(parents=True, exist_ok=True)
